import React, { useState, useEffect } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ReferenceLine, ResponsiveContainer } from 'recharts';

// You'll need to install this package: npm install @google-cloud/local-auth
import { GoogleAuth } from '@google-cloud/local-auth';

// Replace with your actual spreadsheet ID
const SPREADSHEET_ID = '1acsENaf60BuGoJuV78m8556p9VPl3gJX657nSbycLvE';
const RANGE = 'Sheet1!A2:P'; // Adjust this range as needed

const DiscountChart = () => {
  const [data, setData] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const auth = new GoogleAuth({
          keyFilename: 'path/to/your/credentials.json',
          scopes: ['https://www.googleapis.com/auth/spreadsheets.readonly'],
        });

        const client = await auth.getClient();
        const sheets = google.sheets({ version: 'v4', auth: client });

        const response = await sheets.spreadsheets.values.get({
          spreadsheetId: SPREADSHEET_ID,
          range: RANGE,
        });

        const rows = response.data.values;
        if (rows.length) {
          const chartData = rows.map((row) => ({
            day: parseInt(row[0]),
            backingValue: parseFloat(row[10]),
            discountPremium: parseFloat(row[15]),
          }));
          setData(chartData);
        }
      } catch (error) {
        console.error('Error fetching data:', error);
      }
    };

    fetchData();
  }, []);

  return (
    <div style={{ width: '100%', height: 600 }}>
      <h2 style={{ textAlign: 'center' }}>pMaxi <span style={{ color: 'blue' }}>M</span></h2>
      <ResponsiveContainer width="100%" height="100%">
        <LineChart
          data={data}
          margin={{ top: 5, right: 30, left: 20, bottom: 5 }}
        >
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis 
            dataKey="day" 
            label={{ value: 'Day Number', position: 'insideBottomRight', offset: -10 }} 
            type="number"
            domain={['dataMin', 'dataMax']}
          />
          <YAxis domain={[0, 'dataMax']} />
          <Tooltip />
          <Legend />
          <Line 
            type="monotone" 
            dataKey="discountPremium" 
            stroke="#EA4335" 
            dot={false} 
            name="Δ Discount/Premium in HEX" 
            strokeWidth={1.5}
          />
          <Line 
            type="monotone" 
            dataKey="backingValue" 
            stroke="rgb(255, 205, 86)" 
            dot={false} 
            name="Backing Value (Principle + Yield)" 
            strokeWidth={1.5}
          />
          <ReferenceLine 
            x={1255 - 881} 
            stroke="#A101F7" 
            label={{ 
              value: 'PulseChain launch', 
              position: 'top', 
              fill: '#A101F7', 
              fontSize: 12 
            }} 
          />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

export default DiscountChart;
